TablacusExplorer.List:
const Items = await FV.Items(SVGIO_SELECTION | SVGIO_FLAG_VIEWORDER);
const Count = await Items.Count;
if (Count) {
	let nIndex = Math.max(api.SendMessage(FV.hwndList, LVM_GETNEXTITEM, -1, LVIS_SELECTED), 0) - 1;

	const hMenu = await api.CreatePopupMenu();
	const ContextMenu = await api.ContextMenu(Items, FV);
	if (ContextMenu) {
		await ContextMenu.QueryContextMenu(hMenu, 0, 1, 0x7FFF, CMF_DEFAULTONLY);
		await ContextMenu.InvokeCommand(0, ui_.hwnd, CommandID_DELETE - 1, null, null, SW_SHOWNORMAL, 0, 0);
	}
	api.DestroyMenu(hMenu);

	if (nIndex >= 0) {
		FV.SelectItem(nIndex, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
	}
}

const Items = await FV.Items(SVGIO_SELECTION | SVGIO_FLAG_VIEWORDER);
const Count = await Items.Count;
if (Count) {
	let nIndex = Math.max(api.SendMessage(FV.hwndList, LVM_GETNEXTITEM, -1, LVIS_SELECTED), 0) - 1;

	const hMenu = await api.CreatePopupMenu();
	const ContextMenu = await api.ContextMenu(Items, FV);
	if (ContextMenu) {
		await ContextMenu.QueryContextMenu(hMenu, 0, 1, 0x7FFF, CMF_DEFAULTONLY);
		await ContextMenu.InvokeCommand(0, ui_.hwnd, "undelete", null, null, SW_SHOWNORMAL, 0, 0);
	}
	api.DestroyMenu(hMenu);

	if (nIndex >= 0) {
		FV.SelectItem(nIndex, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
	}
}

if (FV.ItemCount(SVGIO_ALLVIEW) > 0) {
	FV.SelectItem(0, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
}

let count = FV.ItemCount(SVGIO_ALLVIEW);
if (count > 0) {
	FV.SelectItem(count - 1, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
}

let nIndex = FV.GetFocusedItem;
if (!api.SendMessage(Ctrl.hwndList, LVM_GETITEMSTATE, nIndex, LVIS_SELECTED)) {
	FV.SelectItem(nIndex, SVSI_SELECT);
} else {
	if (nIndex + 1 < FV.ItemCount(SVGIO_ALLVIEW)) {
		FV.SelectItem(nIndex, SVSI_DESELECT);
		FV.SelectItem(nIndex + 1, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED);
		// FV.SelectItem(nIndex + 1, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
	}
}

let nIndex = FV.GetFocusedItem;
if (!api.SendMessage(Ctrl.hwndList, LVM_GETITEMSTATE, nIndex, LVIS_SELECTED)) {
	FV.SelectItem(nIndex, SVSI_SELECT);
} else {
	nIndex = nIndex + 1;
	if (nIndex < FV.ItemCount(SVGIO_ALLVIEW)) {
		FV.SelectItem(nIndex, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED);
	}
}

let nIndex = FV.GetFocusedItem;
if (!api.SendMessage(Ctrl.hwndList, LVM_GETITEMSTATE, nIndex, LVIS_SELECTED)) {
	FV.SelectItem(nIndex, SVSI_SELECT);
} else {
	if (nIndex - 1 >= 0) {
		FV.SelectItem(nIndex, SVSI_DESELECT);
		FV.SelectItem(nIndex - 1, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED);
		// FV.SelectItem(nIndex - 1, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED | SVSI_DESELECTOTHERS);
	}
}

let nIndex = FV.GetFocusedItem;
if (!api.SendMessage(Ctrl.hwndList, LVM_GETITEMSTATE, nIndex, LVIS_SELECTED)) {
	FV.SelectItem(nIndex, SVSI_SELECT);
} else {
	nIndex = nIndex - 1;
	if (nIndex >= 0) {
		FV.SelectItem(nIndex, SVSI_SELECT | SVSI_ENSUREVISIBLE | SVSI_FOCUSED);
	}
}

var FV = GetFolderView(Ctrl, pt);
if (FV) {
	var hMenu = api.CreatePopupMenu(), hSubMenu;
	var ContextMenu = FV.ViewMenu();
	if (ContextMenu) {
		ContextMenu.QueryContextMenu(hMenu, 0, 1, 0x7fff, CMF_DEFAULTONLY);
		var mii = api.Memory("MENUITEMINFO");
		mii.cbSize = mii.Size;
		mii.fMask = MIIM_SUBMENU;
		for (var i = 0; i < api.GetMenuItemCount(hMenu); i++) {
			api.GetMenuItemInfo(hMenu, i, true, mii);
			if (mii.hSubMenu) {
				hSubMenu = mii.hSubMenu;
				mii.fMask = MIIM_FTYPE | MIIM_STATE;
				for (var j = 0; j < api.GetMenuItemCount(hSubMenu); j++) {
					api.GetMenuItemInfo(hSubMenu, j, true, mii);
					if (mii.fState & MFS_CHECKED && mii.fType & MFT_RADIOCHECK) {
						mii.fMask = MIIM_ID;
						api.GetMenuItemInfo(hSubMenu, j + 1, true, mii);
						if (mii.wID <= 0) {
							api.GetMenuItemInfo(hSubMenu, 0, true, mii);
						}
						ContextMenu.InvokeCommand(0, te.hwnd, mii.wID - 1, null, null, SW_SHOWNORMAL, 0, 0);
						break;
					}
				}
				break;
			}
		}
		api.DestroyMenu(hMenu);
	}
}

var FV = GetFolderView(Ctrl, pt);
if (FV) {
	var hMenu = api.CreatePopupMenu(), hSubMenu;
	var ContextMenu = FV.ViewMenu();
	if (ContextMenu) {
		ContextMenu.QueryContextMenu(hMenu, 0, 1, 0x7fff, CMF_DEFAULTONLY);
		var mii = api.Memory("MENUITEMINFO");
		mii.cbSize = mii.Size;
		mii.fMask = MIIM_SUBMENU;
		for (var i = 0; i < api.GetMenuItemCount(hMenu); i++) {
			api.GetMenuItemInfo(hMenu, i, true, mii);
			if (mii.hSubMenu) {
				hSubMenu = mii.hSubMenu;
				mii.fMask = MIIM_FTYPE | MIIM_STATE;
				for (var j = 0; j < api.GetMenuItemCount(hSubMenu); j++) {
					api.GetMenuItemInfo(hSubMenu, j, true, mii);
					if (mii.fState & MFS_CHECKED && mii.fType & MFT_RADIOCHECK) {
						mii.fMask = MIIM_ID;
						if (j) {
							api.GetMenuItemInfo(hSubMenu, j - 1, true, mii);
						} else {
							mii.fMask = MIIM_ID | MIIM_FTYPE;
							for (var k = 0; k < api.GetMenuItemCount(hSubMenu); k++) {
								api.GetMenuItemInfo(hSubMenu, k, true, mii);
								if (mii.fType & MFT_SEPARATOR) {
									mii.wID = wID;
									break;
								}
								wID = mii.wID;
							}
						}
						if (mii.wID > 0) {
							ContextMenu.InvokeCommand(0, te.hwnd, mii.wID - 1, null, null, SW_SHOWNORMAL, 0, 0);
						}
						break;
					}
				}
				break;
			}
		}
		api.DestroyMenu(hMenu);
	}
}

var TC = te.Ctrl(CTRL_TC);
if (TC && TC.SelectedIndex > 0) {
	TC.Move(TC.SelectedIndex, TC.SelectedIndex - 1);
	return S_OK;
}
return S_FALSE;

var TC = te.Ctrl(CTRL_TC);
if (TC && TC.SelectedIndex < TC.Count - 1) {
	TC.Move(TC.SelectedIndex, TC.SelectedIndex + 1);
	return S_OK;
}
return S_FALSE;

var FV = GetFolderView(Ctrl, pt);
var FV2 = Sync.SwitchPrevPane.Exec(Ctrl);
FV.Parent.Move(FV.Parent.SelectedIndex, FV2.Parent.Count, FV2.Parent);
FV2.Focus();

var FV = GetFolderView(Ctrl, pt);
var FV2 = Sync.SwitchPane.NextFV(Ctrl);
FV.Parent.Move(FV.Parent.SelectedIndex, FV2.Parent.Count, FV2.Parent);
FV2.Focus();
